class NestedIterator:
    def __init__(self, nestedList: [NestedInteger]):
        self.stack = []
        for num in nestedList:
            if num.isInteger():
                self.stack.append(num.getInteger())
            else:
                self.stack.append(num)
        self.index = len(self.stack) - 1

    def next(self) -> int:
        result = self.stack.pop()
        self.index -= 1
        return result

    def hasNext(self) -> bool:
        while self.index >= 0:
            if isinstance(self.stack[self.index], int):
                return True
            if self.stack[self.index].isInteger():
                self.stack.pop()
                self.index -= 1
            else:
                temp = []
                while self.stack[self.index].getList():
                    temp.append(self.stack[self.index].getList().pop())
                self.stack[self.index] = temp
                self.index -= 1
                break
        return False
